290→function sliderThumbCenterPercent(valuePct: number, trackPx: number, thumbPx: number): string {
291→  const clamped = Math.max(0, Math.min(100, valuePct));
292→  const min = thumbPx * 0.5;
293→  const max = Math.max(min, trackPx - thumbPx * 0.5);
294→  const center = min + ((max - min) * clamped) / 100;
295→  return `${(center / trackPx) * 100}%`;
296→}
297→
298→function verticalThumbCenterPx(valuePct: number, trackTopPx: number, trackHeightPx: number, thumbPx: number): string {
299→  const clamped = Math.max(0, Math.min(100, valuePct));
300→  const min = trackTopPx + thumbPx * 0.5;
301→  const max = Math.max(min, trackTopPx + trackHeightPx - thumbPx * 0.5);
302→  const center = min + ((max - min) * clamped) / 100;
303→  return `${center}px`;
304→}
