52→export function handleCheatKey(key: string) {
53→  if (key.length === 1 && /[a-z]/i.test(key)) {
54→    cheatBuffer += key.toLowerCase();
55→    if (cheatBuffer.length > 20) cheatBuffer = cheatBuffer.slice(-20);
56→    for (const [code, fn] of Object.entries(CHEATS)) {
57→      if (cheatBuffer.endsWith(code)) {
58→        fn();
59→        cheatBuffer = '';
60→        break;
61→      }
62→    }
63→  }
64→}
