  9→const modelCache = new Map<Race, ModelType>();
 10→const blpCache = new Map<string, ImageData[]>();
 11→const widgetMaskCache = new Map<Race, string>();
 12→
 13→function computeVisibleBounds2D(model: ModelType): { minX: number; maxX: number; minY: number; maxY: number } | null {
 14→  let minX = Number.POSITIVE_INFINITY, maxX = Number.NEGATIVE_INFINITY;
 15→  let minY = Number.POSITIVE_INFINITY, maxY = Number.NEGATIVE_INFINITY;
 16→  let hasVisible = false;
 17→  for (const geoset of model.Geosets || []) {
 18→    if (!geoset.Faces || geoset.Faces.length === 0) continue;
 19→    const verts = geoset.Vertices;
 20→    for (let i = 0; i < verts.length; i += 3) {
 21→      const x = verts[i]; const y = verts[i + 1];
 22→      if (x < minX) minX = x; if (x > maxX) maxX = x;
 23→      if (y < minY) minY = y; if (y > maxY) maxY = y;
 24→      hasVisible = true;
 25→    }
 26→  }
 27→  return hasVisible ? { minX, maxX, minY, maxY } : null;
 28→}
 29→
 30→function disableBackdropQuads(model: ModelType): void {
 31→  const hiddenNodes = new Set(['plane01', 'sunrise/set']);
 32→  for (const geoset of model.Geosets || []) {
 33→    const nodeIndex = geoset.Groups?.[0]?.[0];
 34→    if (nodeIndex == null) continue;
 35→    const nodeName = model.Nodes?.[nodeIndex]?.Name?.toLowerCase();
 36→    if (!nodeName || !hiddenNodes.has(nodeName)) continue;
 37→    geoset.Faces = new Uint16Array(0);
 38→  }
 39→}
 40→
 41→function getModelPath(race: Race): string {
 42→  return `/models/time-indicator/${RACE_PREFIXES[race].tile}UI-TimeIndicator.mdx`;
 43→}
 44→
 45→function getClockTexturePath(textureImage: string, race: Race): string | null {
 46→  const norm = textureImage.replaceAll('\\', '/').toLowerCase();
 47→  const tile = RACE_PREFIXES[race].tile;
 48→  const base = `/models/time-indicator/textures/${race}/`;
 49→  if (norm.includes('genericglowfaded')) return `${base}GenericGlowFaded.blp`;
 50→  if (norm.includes('star3')) return `${base}star3.blp`;
 51→  if (norm.includes('genericglow2_32')) return `${base}GenericGlow2_32.blp`;
 52→  if (norm.includes('timeindicatorframe')) return `${base}${tile}UITile-TimeIndicatorFrame.blp`;
 53→  if (norm.includes('timeindicator')) return `${base}HumanUITile-TimeIndicator.blp`;
 54→  return null;
 55→}
 56→
 57→function getFrameTexturePath(race: Race): string {
 58→  return `/models/time-indicator/textures/${race}/${RACE_PREFIXES[race].tile}UITile-TimeIndicatorFrame.blp`;
 59→}
 60→
 61→function findTransparentSeed(alpha: Uint8ClampedArray, width: number, height: number, startX: number, startY: number): number {
 62→  const inBounds = (x: number, y: number) => x >= 0 && y >= 0 && x < width && y < height;
 63→  const alphaAt = (x: number, y: number) => alpha[(y * width + x) * 4 + 3];
 64→  if (inBounds(startX, startY) && alphaAt(startX, startY) === 0) return startY * width + startX;
 65→  const maxRadius = Math.max(width, height);
 66→  for (let r = 1; r < maxRadius; r++) {
 67→    for (let dy = -r; dy <= r; dy++) {
 68→      const y = startY + dy;
 69→      const x1 = startX - r; const x2 = startX + r;
 70→      if (inBounds(x1, y) && alphaAt(x1, y) === 0) return y * width + x1;
 71→      if (inBounds(x2, y) && alphaAt(x2, y) === 0) return y * width + x2;
 72→    }
 73→    for (let dx = -r + 1; dx <= r - 1; dx++) {
 74→      const x = startX + dx;
 75→      const y1 = startY - r; const y2 = startY + r;
 76→      if (inBounds(x, y1) && alphaAt(x, y1) === 0) return y1 * width + x;
 77→      if (inBounds(x, y2) && alphaAt(x, y2) === 0) return y2 * width + x;
 78→    }
 79→  }
 80→  return -1;
 81→}
 82→
 83→async function loadWidgetMaskDataUrl(race: Race): Promise<string> {
 84→  const cached = widgetMaskCache.get(race);
 85→  if (cached) return cached;
 86→  const frame = (await loadBLPMips(getFrameTexturePath(race)))[0];
 87→  if (!frame || frame.width <= 0 || frame.height <= 0) throw new Error(`Invalid frame texture for ${race}`);
 88→  const width = frame.width; const height = frame.height;
 89→  const seedX = Math.round(width * 0.49); const seedY = Math.round(height * 0.34);
 90→  const seed = findTransparentSeed(frame.data, width, height, seedX, seedY);
 91→  if (seed < 0) throw new Error(`Unable to locate clock aperture for ${race}`);
 92→  const aperture = new Uint8Array(width * height);
 93→  const queue = new Int32Array(width * height);
 94→  let head = 0; let tail = 0;
 95→  queue[tail++] = seed; aperture[seed] = 1;
 96→  while (head < tail) {
 97→    const cur = queue[head++]; const x = cur % width; const y = (cur / width) | 0;
 98→    for (const [nx, ny] of [[x-1,y],[x+1,y],[x,y-1],[x,y+1]]) {
 99→      if (nx < 0 || ny < 0 || nx >= width || ny >= height) continue;
100→      const next = ny * width + nx;
101→      if (aperture[next]) continue;
102→      if (frame.data[next * 4 + 3] !== 0) continue;
103→      aperture[next] = 1; queue[tail++] = next;
104→    }
105→  }
106→  const pixels = new Uint8ClampedArray(width * height * 4);
107→  for (let i = 0; i < width * height; i++) {
108→    const keep = frame.data[i * 4 + 3] > 0 || aperture[i] === 1;
109→    if (!keep) continue;
110→    const p = i * 4; pixels[p] = 255; pixels[p+1] = 255; pixels[p+2] = 255; pixels[p+3] = 255;
111→  }
112→  const canvas = document.createElement('canvas'); canvas.width = width; canvas.height = height;
113→  const ctx = canvas.getContext('2d');
114→  if (!ctx) throw new Error('Failed to create widget mask canvas');
115→  ctx.putImageData(new ImageData(pixels, width, height), 0, 0);
116→  const dataUrl = canvas.toDataURL('image/png');
117→  widgetMaskCache.set(race, dataUrl);
118→  return dataUrl;
119→}
120→
121→async function loadModelForRace(race: Race): Promise<ModelType> {
122→  const cached = modelCache.get(race);
123→  if (cached) return cached;
124→  const res = await fetch(getModelPath(race));
125→  if (!res.ok) throw new Error(`Failed to fetch clock model for ${race}`);
126→  const ab = await res.arrayBuffer();
127→  const model = parseMDX(ab);
128→  disableBackdropQuads(model);
129→  modelCache.set(race, model);
130→  return model;
131→}
132→
133→async function loadBLPMips(path: string): Promise<ImageData[]> {
134→  const cached = blpCache.get(path);
135→  if (cached) return cached;
136→  const res = await fetch(path);
137→  if (!res.ok) throw new Error(`Failed to fetch texture ${path}`);
138→  const ab = await res.arrayBuffer();
139→  const blp = decodeBLP(ab);
140→  const mips: ImageData[] = [];
141→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
142→  for (let i = 0; i < maxLevels; i++) {
143→    const w = blp.width >> i; const h = blp.height >> i;
144→    if (w <= 0 || h <= 0) break;
145→    try {
146→      const img = getBLPImageData(blp, i);
147→      if (!img || !img.width || !img.height) break;
148→      mips.push(new ImageData(new Uint8ClampedArray(img.data), img.width, img.height));
149→      if (img.width === 1 && img.height === 1) break;
150→    } catch { break; }
151→  }
152→  if (mips.length === 0) throw new Error(`No mip levels decoded for ${path}`);
153→  blpCache.set(path, mips);
154→  return mips;
155→}
