159→export default function TimeIndicatorModel(props: TimeIndicatorModelProps) {
160→  const canvasRef = useRef<HTMLCanvasElement>(null);
161→  const [widgetMaskUrl, setWidgetMaskUrl] = useState('');
162→  const stateRef = useRef({
163→    gl: null as WebGLRenderingContext | WebGL2RenderingContext | null,
164→    modelRenderer: null as ModelRenderer | null,
165→    rafId: 0,
166→    resizeObserver: null as ResizeObserver | null,
167→    disposed: false,
168→    initVersion: 0,
169→    viewMinX: 0, viewMaxX: 1, viewMinY: 0, viewMaxY: 1,
170→    mvMatrix: mat4.create(),
171→    pMatrix: mat4.create(),
172→  });
173→
174→  useEffect(() => {
175→    const s = stateRef.current;
176→    const canvas = canvasRef.current!;
177→
178→    const destroyRenderer = () => {
179→      if (!s.modelRenderer) return;
180→      try { s.modelRenderer.destroy(); } catch (err) { console.warn('clock renderer destroy failed', err); }
181→      finally { s.modelRenderer = null; }
182→    };
183→
184→    const resizeCanvas = () => {
185→      if (!s.gl) return;
186→      const dpr = window.devicePixelRatio || 1;
187→      const w = Math.max(1, Math.round(canvas.clientWidth * dpr));
188→      const h = Math.max(1, Math.round(canvas.clientHeight * dpr));
189→      if (canvas.width !== w || canvas.height !== h) { canvas.width = w; canvas.height = h; }
190→      s.gl.viewport(0, 0, w, h);
191→    };
192→
193→    const startRenderLoop = () => {
194→      const startTs = performance.now();
195→      const tick = (now: number) => {
196→        if (s.disposed) return;
197→        s.rafId = requestAnimationFrame(tick);
198→        if (!s.gl || !s.modelRenderer) return;
199→        resizeCanvas();
200→        const frame = ((now - startTs) * 1.0) % 60000;
201→        s.modelRenderer.setSequence(0);
202→        s.modelRenderer.setFrame(frame);
203→        s.modelRenderer.update(0);
204→        mat4.identity(s.mvMatrix);
205→        const baseW = Math.max(1e-6, s.viewMaxX - s.viewMinX);
206→        const baseH = Math.max(1e-6, s.viewMaxY - s.viewMinY);
207→        const cx = (s.viewMinX + s.viewMaxX) * 0.5;
208→        const cy = (s.viewMinY + s.viewMaxY) * 0.5;
209→        const canvasAspect = Math.max(1e-6, canvas.clientWidth / Math.max(1, canvas.clientHeight));
210→        const modelAspect = baseW / baseH;
211→        let viewW = baseW * 1.04; let viewH = baseH * 1.04;
212→        if (canvasAspect > modelAspect) viewW = viewH * canvasAspect;
213→        else viewH = viewW / canvasAspect;
214→        mat4.ortho(s.pMatrix, cx - viewW * 0.5, cx + viewW * 0.5, cy - viewH * 0.5, cy + viewH * 0.5, -10, 10);
215→        s.gl.clearColor(0, 0, 0, 0);
216→        s.gl.clear(s.gl.COLOR_BUFFER_BIT | s.gl.DEPTH_BUFFER_BIT);
217→        s.modelRenderer.render(s.mvMatrix, s.pMatrix, { env: false, wireframe: false });
218→      };
219→      s.rafId = requestAnimationFrame(tick);
220→    };
221→
222→    const initForRace = async (race: Race) => {
223→      const version = ++s.initVersion;
224→      const model = await loadModelForRace(race);
225→      if (s.disposed || version !== s.initVersion) return;
226→      destroyRenderer();
227→      s.modelRenderer = new ModelRenderer(model);
228→      s.modelRenderer.initGL(s.gl!);
229→      s.modelRenderer.setCamera(vec3.fromValues(0, 0, 2), quat.fromValues(0, 0, 0, 1));
230→      s.modelRenderer.setLightPosition(vec3.fromValues(0, 0, 2));
231→      s.modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
232→      const bounds = computeVisibleBounds2D(model);
233→      if (bounds) {
234→        s.viewMinX = bounds.minX; s.viewMaxX = bounds.maxX;
235→        s.viewMinY = bounds.minY; s.viewMaxY = bounds.maxY;
236→      } else {
237→        const extMin = model.Info?.MinimumExtent; const extMax = model.Info?.MaximumExtent;
238→        if (extMin && extMax) { s.viewMinX = extMin[0]; s.viewMaxX = extMax[0]; s.viewMinY = extMin[1]; s.viewMaxY = extMax[1]; }
239→      }
240→      const texturePromises = (model.Textures || []).map(async (tex) => {
241→        const path = getClockTexturePath(tex.Image, race);
242→        if (!path) return;
243→        const mips = await loadBLPMips(path);
244→        if (!s.disposed && version === s.initVersion) s.modelRenderer!.setTextureImageData(tex.Image, mips);
245→      });
246→      const [maskUrl] = await Promise.all([loadWidgetMaskDataUrl(race), Promise.all(texturePromises)]);
247→      if (s.disposed || version !== s.initVersion) return;
248→      setWidgetMaskUrl(maskUrl);
249→      s.modelRenderer.setSequence(0);
250→    };
251→
252→    (s as any).initForRace = initForRace;
253→
254→    s.gl = canvas.getContext('webgl2', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false }) as WebGL2RenderingContext | null;
255→    if (!s.gl) s.gl = canvas.getContext('webgl', { alpha: true, premultipliedAlpha: false, antialias: true, depth: true, stencil: false });
256→    if (!s.gl) return;
257→
258→    resizeCanvas();
259→    s.resizeObserver = new ResizeObserver(() => resizeCanvas());
260→    s.resizeObserver.observe(canvas);
261→    startRenderLoop();
262→    void initForRace(props.race);
263→
264→    return () => {
265→      s.disposed = true; s.initVersion++;
266→      cancelAnimationFrame(s.rafId);
267→      s.resizeObserver?.disconnect();
268→      destroyRenderer();
269→    };
270→  }, []);
271→
272→  useEffect(() => {
273→    const s = stateRef.current;
274→    if (!s.gl || s.disposed) return;
275→    const initForRace = (s as any).initForRace as ((race: Race) => Promise<void>) | undefined;
276→    if (initForRace) void initForRace(props.race);
277→  }, [props.race]);
278→
279→  return (
280→    <canvas
281→      ref={canvasRef}
282→      style={{
283→        position: 'absolute', inset: '0', width: '100%', height: '100%', display: 'block', pointerEvents: 'none',
284→        maskImage: widgetMaskUrl ? `url("${widgetMaskUrl}")` : 'none',
285→        WebkitMaskImage: widgetMaskUrl ? `url("${widgetMaskUrl}")` : 'none',
286→        maskRepeat: 'no-repeat', WebkitMaskRepeat: 'no-repeat',
287→        maskSize: '100% 100%', WebkitMaskSize: '100% 100%',
288→        maskPosition: 'center', WebkitMaskPosition: 'center',
289→      } as React.CSSProperties}
290→    />
291→  );
292→}
