107→export default function TopHudWebGL(props: Props) {
108→  const canvasRef = useRef<HTMLCanvasElement>(null);
109→  const propsRef = useRef(props);
110→  propsRef.current = props;
111→
112→  const stateRef = useRef<GLState>({
113→    gl: null,
114→    program: null,
115→    quadBuffer: null,
116→    positionLoc: -1,
117→    uvLoc: -1,
118→    textureLoc: null,
119→    destroyed: false,
120→    drawQueued: false,
121→    drawRaf: 0,
122→    resizeObserver: null,
123→    textureCache: new Map(),
124→    textureLoadCache: new Map(),
125→    activeTextures: null,
126→  });
127→
128→  useEffect(() => {
129→    const s = stateRef.current;
130→    const canvas = canvasRef.current!;
131→
132→    const syncCanvasSize = () => {
133→      if (!s.gl) return;
134→      const dpr = window.devicePixelRatio || 1;
135→      const cssWidth = Math.max(1, canvas.clientWidth || 1);
136→      const cssHeight = Math.max(1, canvas.clientHeight || 1);
137→      const width = Math.round(cssWidth * dpr);
138→      const height = Math.round(cssHeight * dpr);
139→      if (canvas.width !== width || canvas.height !== height) {
140→        canvas.width = width;
141→        canvas.height = height;
142→      }
143→      s.gl.viewport(0, 0, width, height);
144→    };
145→
146→    const drawQuad = (
147→      texture: WebGLTexture,
148→      x: number, y: number, w: number, h: number,
149→      u0: number, v0: number, u1: number, v1: number
150→    ) => {
151→      if (!s.gl || !s.quadBuffer) return;
152→      const canvasW = canvas.width;
153→      const canvasH = canvas.height;
154→      if (canvasW <= 0 || canvasH <= 0 || w <= 0 || h <= 0) return;
155→      const x0 = (x / canvasW) * 2 - 1;
156→      const y0 = 1 - (y / canvasH) * 2;
157→      const x1 = ((x + w) / canvasW) * 2 - 1;
158→      const y1 = 1 - ((y + h) / canvasH) * 2;
159→      const vertices = new Float32Array([
160→        x0, y0, u0, v0, x1, y0, u1, v0, x0, y1, u0, v1,
161→        x1, y0, u1, v0, x1, y1, u1, v1, x0, y1, u0, v1,
162→      ]);
163→      s.gl.bindTexture(s.gl.TEXTURE_2D, texture);
164→      s.gl.bindBuffer(s.gl.ARRAY_BUFFER, s.quadBuffer);
165→      s.gl.bufferData(s.gl.ARRAY_BUFFER, vertices, s.gl.STREAM_DRAW);
166→      s.gl.drawArrays(s.gl.TRIANGLES, 0, 6);
167→    };
168→
169→    const draw = () => {
170→      if (!s.gl || !s.program || !s.quadBuffer || !s.activeTextures) return;
171→      syncCanvasSize();
172→      const canvasW = canvas.width;
173→      const canvasH = canvas.height;
174→      if (canvasW <= 0 || canvasH <= 0) return;
175→      s.gl.clear(s.gl.COLOR_BUFFER_BIT);
176→      s.gl.useProgram(s.program);
177→      s.gl.bindBuffer(s.gl.ARRAY_BUFFER, s.quadBuffer);
178→      s.gl.enableVertexAttribArray(s.positionLoc);
179→      s.gl.vertexAttribPointer(s.positionLoc, 2, s.gl.FLOAT, false, 16, 0);
180→      s.gl.enableVertexAttribArray(s.uvLoc);
181→      s.gl.vertexAttribPointer(s.uvLoc, 2, s.gl.FLOAT, false, 16, 8);
182→      s.gl.activeTexture(s.gl.TEXTURE0);
183→      s.gl.uniform1i(s.textureLoc, 0);
184→
185→      const dpr = window.devicePixelRatio || 1;
186→      const seamPx = SEAM_PX * dpr;
187→      const vw = canvasW / 100;
188→      const topHudH = canvasH;
189→      const p = propsRef.current;
190→
191→      if (p.leftOnly) {
192→        const leftSpanVw = LEFT_TILE1_WIDTH_VW + LEFT_TILE2_WIDTH_VW;
193→        const leftTile1W = (LEFT_TILE1_WIDTH_VW / leftSpanVw) * canvasW + seamPx;
194→        const leftTile2X = leftTile1W - seamPx;
195→        const leftTile2W = canvasW - leftTile2X;
196→        drawQuad(s.activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
197→        drawQuad(s.activeTextures[2], leftTile2X, 0, leftTile2W, topHudH, TILE2_LEFT_U0, TOP_SLICE_V0, TILE2_LEFT_U1, TOP_SLICE_V1);
198→        return;
199→      }
200→
201→      const leftTile1W = LEFT_TILE1_WIDTH_VW * vw + seamPx;
202→      const leftTile2W = LEFT_TILE2_WIDTH_VW * vw + seamPx;
203→      const leftTile2X = leftTile1W - seamPx;
204→      drawQuad(s.activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
205→      drawQuad(s.activeTextures[2], leftTile2X, 0, leftTile2W, topHudH, TILE2_LEFT_U0, TOP_SLICE_V0, TILE2_LEFT_U1, TOP_SLICE_V1);
206→
207→      const rightTile2W = RIGHT_TILE2_WIDTH_VW * vw + seamPx;
208→      const rightTile3W = RIGHT_TILE3_WIDTH_VW * vw + seamPx;
209→      const rightTile4W = RIGHT_TILE4_WIDTH_VW * vw + seamPx;
210→      const rightTile4X = canvasW - rightTile4W;
211→      const rightTile3X = rightTile4X - (rightTile3W - seamPx);
212→      const rightTile2X = rightTile3X - (rightTile2W - seamPx);
213→      drawQuad(s.activeTextures[2], rightTile2X, 0, rightTile2W, topHudH, TILE2_RIGHT_U0, TOP_SLICE_V0, TILE2_RIGHT_U1, TOP_SLICE_V1);
214→      drawQuad(s.activeTextures[3], rightTile3X, 0, rightTile3W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
215→      drawQuad(s.activeTextures[4], rightTile4X, 0, rightTile4W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
216→    };
217→
218→    const requestDraw = () => {
219→      if (s.drawQueued || s.destroyed) return;
220→      s.drawQueued = true;
221→      s.drawRaf = window.requestAnimationFrame(() => {
222→        s.drawQueued = false;
223→        draw();
224→      });
225→    };
226→
227→    const loadTexture = (path: string): Promise<WebGLTexture | null> => {
228→      if (!s.gl) return Promise.resolve(null);
229→      const cached = s.textureCache.get(path);
230→      if (cached) return Promise.resolve(cached);
231→      const inflight = s.textureLoadCache.get(path);
232→      if (inflight) return inflight;
233→
234→      const promise = new Promise<WebGLTexture | null>((resolve) => {
235→        const image = new Image();
236→        image.onload = () => {
237→          if (!s.gl || s.destroyed) { s.textureLoadCache.delete(path); resolve(null); return; }
238→          const texture = s.gl.createTexture();
239→          if (!texture) { s.textureLoadCache.delete(path); resolve(null); return; }
240→          s.gl.bindTexture(s.gl.TEXTURE_2D, texture);
241→          s.gl.texImage2D(s.gl.TEXTURE_2D, 0, s.gl.RGBA, s.gl.RGBA, s.gl.UNSIGNED_BYTE, image);
242→          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_MIN_FILTER, s.gl.LINEAR);
243→          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_MAG_FILTER, s.gl.LINEAR);
244→          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_WRAP_S, s.gl.CLAMP_TO_EDGE);
245→          s.gl.texParameteri(s.gl.TEXTURE_2D, s.gl.TEXTURE_WRAP_T, s.gl.CLAMP_TO_EDGE);
246→          s.textureCache.set(path, texture);
247→          s.textureLoadCache.delete(path);
248→          resolve(texture);
249→        };
250→        image.onerror = () => {
251→          console.error(`Failed to load top HUD texture: ${path}`);
252→          s.textureLoadCache.delete(path);
253→          resolve(null);
254→        };
255→        image.src = path;
256→      });
257→      s.textureLoadCache.set(path, promise);
258→      return promise;
259→    };
260→
261→    const loadRaceTextures = async (race: Race) => {
262→      if (!s.gl || s.destroyed) return;
263→      const paths = TILE_INDICES.map((index) => topTilePath(race, index));
264→      const loaded = await Promise.all(paths.map((path) => loadTexture(path)));
265→      if (s.destroyed || loaded.some((tex) => tex === null)) return;
266→      s.activeTextures = { 1: loaded[0]!, 2: loaded[1]!, 3: loaded[2]!, 4: loaded[3]! };
267→      requestDraw();
268→    };
269→
270→    // Store for use in race/leftOnly effects
271→    (stateRef.current as any).loadRaceTextures = loadRaceTextures;
272→    (stateRef.current as any).requestDraw = requestDraw;
273→
274→    s.gl = canvas.getContext('webgl', {
275→      alpha: true, premultipliedAlpha: false, antialias: false, depth: false, stencil: false,
276→    });
277→    if (!s.gl) { console.error('WebGL is unavailable for top HUD rendering.'); return; }
278→
279→    s.program = createProgram(s.gl);
280→    if (!s.program) return;
281→
282→    s.positionLoc = s.gl.getAttribLocation(s.program, 'a_position');
283→    s.uvLoc = s.gl.getAttribLocation(s.program, 'a_uv');
284→    s.textureLoc = s.gl.getUniformLocation(s.program, 'u_texture');
285→    s.quadBuffer = s.gl.createBuffer();
286→
287→    if (s.positionLoc < 0 || s.uvLoc < 0 || !s.textureLoc || !s.quadBuffer) {
288→      console.error('Failed to initialize top HUD WebGL buffers.');
289→      return;
290→    }
291→
292→    s.gl.disable(s.gl.DEPTH_TEST);
293→    s.gl.disable(s.gl.CULL_FACE);
294→    s.gl.enable(s.gl.BLEND);
295→    s.gl.blendFunc(s.gl.SRC_ALPHA, s.gl.ONE_MINUS_SRC_ALPHA);
296→    s.gl.clearColor(0, 0, 0, 0);
297→
298→    void loadRaceTextures(propsRef.current.race);
299→    requestDraw();
300→

500→    cropCtx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
501→    return cropCanvas.toDataURL('image/png');
502→  })();
503→
504→  croppedImageRegionCache.set(key, promise);
505→  return promise;
506→}
